package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat formatMock;
    private Reader readerMock;

    @BeforeEach
    void setup() {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);
    }

    @Test
    void testParse_CreatesNewCSVParserInstance() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    when(mock.getRecordNumber()).thenReturn(0L);
                })) {
            CSVParser parser = CSVParser.parse(readerMock, formatMock);
            assertNotNull(parser);
            assertTrue(parser instanceof CSVParser);
            // verify constructor called with correct args
            assertEquals(1, mocked.constructed().size());
            CSVParser constructed = mocked.constructed().get(0);
            assertNotNull(constructed);
        }
    }

    @Test
    void testParse_ThrowsIOExceptionWhenConstructorThrows() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    throw new IOException("Constructor failure");
                })) {
            IOException thrown = assertThrows(IOException.class, () -> {
                CSVParser.parse(readerMock, formatMock);
            });
            assertEquals("Constructor failure", thrown.getMessage());
        }
    }
}
